#!/bin/bash
set +H  # Disable history expansion to avoid ! issues
set -e

PROJECT_DIR="/root/viralfaceless-ai"
cd "$PROJECT_DIR"

echo "=== ViralFaceless AI - Full Deploy ==="
echo "Started at: $(date)"

# ============================================
# Step 1: Create all necessary directories
# ============================================
echo "[1/7] Creating directories..."
mkdir -p src/components/viralfaceless
mkdir -p src/components/ui
mkdir -p src/lib
mkdir -p src/app/api/ideas/generate
mkdir -p src/app/api/scripts/generate
mkdir -p src/app/api/analytics
mkdir -p src/app/api/auth/register
mkdir -p src/app/api/auth/login
mkdir -p prisma
mkdir -p public

# ============================================
# Step 2: Write all project files via base64
# ============================================
echo "[2/7] Writing project files..."
echo '' | base64 -d > 'src/components/viralfaceless/AppShell.tsx'
echo '' | base64 -d > 'src/components/viralfaceless/IdeaGenerator.tsx'
echo '' | base64 -d > 'src/components/viralfaceless/IdeasList.tsx'
echo '' | base64 -d > 'src/components/viralfaceless/ScriptPanel.tsx'
echo '' | base64 -d > 'src/components/viralfaceless/AnalyticsPanel.tsx'
echo '' | base64 -d > 'src/components/viralfaceless/AuthForm.tsx'
echo '' | base64 -d > 'src/components/viralfaceless/IdeaCard.tsx'
echo '' | base64 -d > 'src/components/ui/button.tsx'
echo '' | base64 -d > 'src/components/ui/badge.tsx'
echo '' | base64 -d > 'src/components/ui/separator.tsx'
echo '' | base64 -d > 'src/components/ui/tabs.tsx'
echo '' | base64 -d > 'src/components/ui/avatar.tsx'
echo '' | base64 -d > 'src/components/ui/card.tsx'
echo '' | base64 -d > 'src/components/ui/input.tsx'
echo '' | base64 -d > 'src/components/ui/label.tsx'
echo '' | base64 -d > 'src/components/ui/select.tsx'
echo '' | base64 -d > 'src/components/ui/skeleton.tsx'
echo 'aW1wb3J0IHsgY2xzeCwgdHlwZSBDbGFzc1ZhbHVlIH0gZnJvbSAiY2xzeCIKaW1wb3J0IHsgdHdNZXJnZSB9IGZyb20gInRhaWx3aW5kLW1lcmdlIgoKZXhwb3J0IGZ1bmN0aW9uIGNuKC4uLmlucHV0czogQ2xhc3NWYWx1ZVtdKSB7CiAgcmV0dXJuIHR3TWVyZ2UoY2xzeChpbnB1dHMpKQp9Cg==' | base64 -d > 'src/lib/utils.ts'
echo '' | base64 -d > 'src/lib/db.ts'
echo '' | base64 -d > 'src/lib/auth.ts'
echo '' | base64 -d > 'src/lib/store.ts'
echo 'aW1wb3J0IHsgQXBwU2hlbGwgfSBmcm9tICdAL2NvbXBvbmVudHMvdmlyYWxmYWNlbGVzcy9BcHBTaGVsbCc7CgpleHBvcnQgZGVmYXVsdCBmdW5jdGlvbiBIb21lKCkgewogIHJldHVybiA8QXBwU2hlbGwgLz47Cn0K' | base64 -d > 'src/app/page.tsx'
echo '' | base64 -d > 'src/app/layout.tsx'
echo '' | base64 -d > 'src/app/globals.css'
echo '' | base64 -d > 'prisma/schema.prisma'
echo '' | base64 -d > 'tsconfig.json'
echo 'Y29uc3QgY29uZmlnID0gewogIHBsdWdpbnM6IFsiQHRhaWx3aW5kY3NzL3Bvc3Rjc3MiXSwKfTsKCmV4cG9ydCBkZWZhdWx0IGNvbmZpZzsK' | base64 -d > 'postcss.config.mjs'
echo '' | base64 -d > 'components.json'
echo '' | base64 -d > 'src/app/api/ideas/generate/route.ts'
echo '' | base64 -d > 'src/app/api/ideas/generate/prompt.ts'
echo '' | base64 -d > 'src/app/api/ideas/route.ts'
echo '' | base64 -d > 'src/app/api/scripts/generate/route.ts'
echo '' | base64 -d > 'src/app/api/analytics/route.ts'
echo '' | base64 -d > 'src/app/api/auth/register/route.ts'
echo '' | base64 -d > 'src/app/api/auth/login/route.ts'
echo 'aW1wb3J0IHR5cGUgeyBOZXh0Q29uZmlnIH0gZnJvbSAibmV4dCI7Cgpjb25zdCBuZXh0Q29uZmlnOiBOZXh0Q29uZmlnID0gewogIC8qIGNvbmZpZyBvcHRpb25zIGhlcmUgKi8KICB0eXBlc2NyaXB0OiB7CiAgICBpZ25vcmVCdWlsZEVycm9yczogdHJ1ZSwKICB9LAogIHJlYWN0U3RyaWN0TW9kZTogZmFsc2UsCn07CgpleHBvcnQgZGVmYXVsdCBuZXh0Q29uZmlnOwo=' | base64 -d > 'next.config.ts'

# ============================================
# Step 3: Fix package.json scripts and deps
# ============================================
echo "[3/7] Fixing package.json..."
echo '' | base64 -d > /tmp/fix-pkg.js
node /tmp/fix-pkg.js
rm -f /tmp/fix-pkg.js

# ============================================
# Step 4: Install dependencies
# ============================================
echo "[4/7] Installing dependencies..."
bun install

# ============================================
# Step 5: Generate Prisma client
# ============================================
echo "[5/7] Generating Prisma client..."
bunx prisma generate
bunx prisma db push --skip-generate 2>/dev/null || true

# ============================================
# Step 6: Rebuild Docker
# ============================================
echo "[6/7] Rebuilding Docker..."
docker compose down 2>/dev/null || true
docker compose up -d --build

# ============================================
# Step 7: Health check
# ============================================
echo "[7/7] Waiting for app to start..."
sleep 10

echo ""
echo "============================================"
echo "  ViralFaceless AI - Deploy Complete!"
echo "============================================"
echo ""
echo "Check status with:"
echo "  docker compose ps"
echo "  docker compose logs -f"
echo ""
echo "Health check:"
echo "  curl -s http://localhost:3000 | head -20"
echo ""
echo "To restart:"
echo "  docker compose restart"
echo ""
echo "To view logs:"
echo "  docker compose logs -f --tail=100"
echo ""
echo "Finished at: $(date)"
